#include <iostream>
using namespace std;

class Complex {
private:
 int real, imag;
public:
 Complex(int r = 0, int i = 0) : real(r), imag(i) {}

 // Friend function declaration
 friend Complex operator+(const Complex& c1, const Complex& c2);

 void display() {
 cout << real << " + " << imag << "i" << endl;
 }
};

// Friend function definition (outside class)
Complex operator+(const Complex& c1, const Complex& c2) {
 Complex result;
 result.real = c1.real + c2.real;
 result.imag = c1.imag + c2.imag;
 return result; // Note: return by value for temporary
}

int main() {
 Complex c1(3, 4), c2(1, 2), c3;
 c3 = c1 + c2; // Equivalent to operator+(c1, c2)
 c3.display(); // Output: 4 + 6i
 return 0;
}

#include <iostream>
using namespace std;

class Person {
private:
 string name;
 int age;
public:
 Person() : name(""), age(0) {}
 Person(string n, int a) : name(n), age(a) {}

 // Friend declarations for stream operators
 friend ostream& operator<<(ostream&, const Person&);
 friend istream& operator>>(istream&, Person&);
};

// Overload << operator
ostream& operator<<(ostream& out, const Person& p) {
 out << "Name: " << p.name << ", Age: " << p.age;
 return out; // Return stream for chaining
}

// Overload >> operator
istream& operator>>(istream& in, Person& p) {
 cout << "Enter name: ";
 in >> p.name;
 cout << "Enter age: ";
 in >> p.age;
 return in;
}

int main() {
 Person p1, p2;
 cin >> p1 >> p2; // Chained input
 cout << p1 << endl << p2; // Chained output
 return 0;
}

#include <iostream>
using namespace std;

class Vector {
private:
 int x, y;
public:
 Vector(int a = 0, int b = 0) : x(a), y(b) {}

 // Friend declaration for unary operator
 friend Vector operator-(const Vector& v);

 void display() {
 cout << "(" << x << ", " << y << ")" << endl;
 }
};

// Unary operator overloading (only 1 parameter)
Vector operator-(const Vector& v) {
 Vector result;
 result.x = -v.x;
 result.y = -v.y;
 return result;
}

int main() {
 Vector v1(5, 3), v2;
 v2 = -v1; // Equivalent to operator-(v1)
 v1.display(); // (5, 3)
 v2.display(); // (-5, -3)
 return 0;
}

#include <iostream>
using namespace std;

class Number {
private:
 int val;
public:
 Number(int v = 0) : val(v) {}

 // Friend declaration
 friend Number& operator+(Number& n1, Number& n2);

 int getVal() const { return val; }
 void setVal(int v) { val = v; }
};

// Returns reference to enable chaining
Number& operator+(Number& n1, Number& n2) {
 n1.val = n1.val + n2.val;
 return n1; // Return same object by reference
}

int main() {
 Number a(10), b(20), c(30);

 // Without return by reference, this won't work
 a + b + c; // Chaining: (a+b) then result+c
 cout << a.getVal(); // Output: 60
 return 0;
}
